mapper.select:
SELECT DISTINCT u.id, u.tenant_id, t.tenant_name, u.username, u.real_name, CASE WHEN u.user_type = 0 THEN 0 WHEN sut.member_type = 1 THEN 1 ELSE 2 END AS user_type, u.user_client, u.email, u.phone, u.id_card, u.gender, u.user_status, u.avatar, u.region_code, u.last_login_time, u.last_login_ip, u.login_count, u.remark, u.create_dept, u.create_by, u.create_time, u.update_by, u.update_time FROM sys_user_org_role ur INNER JOIN sys_user u ON u.id = ur.user_id AND u.del_flag = 0 INNER JOIN sys_user_tenant sut ON sut.user_id = u.id AND sut.tenant_id = ur.tenant_id AND sut.status = 1 INNER JOIN sys_tenant t ON t.id = ur.tenant_id AND t.del_flag = 0 WHERE ur.role_id = #{query.roleId} AND ur.tenant_id = #{query.tenantId}
AND ur.org_id = #{query.orgId}
AND u.username LIKE CONCAT('%', #{query.username}, '%')
AND u.real_name LIKE CONCAT('%', #{query.realName}, '%')
AND u.phone = #{query.phone}
AND u.user_status = #{query.userStatus}
ORDER BY u.create_time DESC

SELECT COUNT(1)
FROM sys_user_org_role
WHERE role_id = #{roleId}
  AND tenant_id = #{tenantId}

SELECT COUNT(DISTINCT u.id) FROM sys_user u LEFT JOIN sys_user_tenant sut ON sut.user_id = u.id AND sut.tenant_id = #{tenantId} AND sut.status = 1 WHERE u.id IN
#{userId}
AND (u.user_type = 0 OR sut.user_id IS NOT NULL)

SELECT COUNT(DISTINCT u.id) FROM sys_user u LEFT JOIN sys_user_tenant sut ON sut.user_id = u.id AND sut.tenant_id = #{tenantId} AND sut.status = 1 WHERE u.id IN
#{userId}
AND (u.user_type = 0 OR sut.member_type = 1)
